/**
 * Workspace Scheduler Proposal V1 — the governed scheduler-provider lane,
 * modeled one-to-one on the resolver studio (lib/workspace-resolver-proposal.js).
 *
 * A resolver shapes an API response into rows; a scheduler provisions a
 * persistent, recurring serverless run. Both are SERVER ARTIFACTS, not workspace
 * config — so this lane uses the same boundary:
 *
 *   - type "scheduler.create", affectedField "server-file" (never a PATCH key)
 *   - the generated file is confined to lib/adapters/integrations/schedulers/
 *   - the provider secret is read from server env at run time — never inlined
 *   - it emits a receipt; "state → eligibility → guidance → action → evidence"
 *     closes exactly as the resolver lane does
 *
 * The generated artifact is the externalized endpoint the user deploys. It
 * carries a PARSEABLE provenance banner (finding 12) so the drift guard can tell
 * generated/stale/orphaned/hand-edited apart, and an HONEST security posture
 * (finding 7): qstash endpoints verify the real Upstash-Signature; supabase-edge
 * endpoints use a clearly-labeled shared-secret check.
 *
 * Provider truth (capabilities, auth candidates, normalization) is single-sourced
 * from lib/scheduler-providers.js — this module never re-implements it.
 *
 * PURE (build/validate/generate). The confined fs write lives in
 * lib/server-scheduler-write.js (server-only).
 */

import { cadenceToCron, normalizeCadence } from "./scheduler-cadence.js";
import { KNOWN_SCHEDULER_PROVIDERS, normalizeProvider, providerCaps, authCandidates } from "./scheduler-providers.js";

const SCHEDULER_PROPOSAL_TYPE = "scheduler.create";
const SCHEDULER_AFFECTED_FIELD = "server-file";
const SCHEDULER_DIR = "lib/adapters/integrations/schedulers";
const SCHEDULER_CONNECTOR_KIND = "scheduler";
// The marker the drift guard greps for, plus the artifact contract version.
const SCHEDULER_ARTIFACT_MARKER = "growthub:scheduler-artifact";
const SCHEDULER_ARTIFACT_VERSION = 1;
// Re-export so existing importers keep working without a second source of truth.
const SCHEDULER_PROVIDERS = KNOWN_SCHEDULER_PROVIDERS;

function clean(value) {
  return String(value == null ? "" : value).trim();
}

function slugify(value, fallback = "scheduler") {
  const slug = clean(value)
    .toLowerCase()
    .replace(/\.js$/, "")
    .replace(/[^a-z0-9-]/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 64);
  return slug || fallback;
}

function resolveSchedulerFilePath(integrationId, provider) {
  const base = `${slugify(integrationId, "scheduler")}-${normalizeProvider(provider)}`;
  if (base.includes("/") || base.includes("..")) {
    return { ok: false, path: null, filename: null, dir: SCHEDULER_DIR, error: "scheduler filename must not contain path segments" };
  }
  const filename = `${base}.js`;
  return { ok: true, path: `${SCHEDULER_DIR}/${filename}`, filename, dir: SCHEDULER_DIR, error: null };
}

function safeJsString(value) {
  return JSON.stringify(clean(value));
}

/** Parseable provenance banner — a single JSON line the drift guard can read. */
function buildArtifactBanner(meta) {
  const payload = {
    v: SCHEDULER_ARTIFACT_VERSION,
    schedulerIntegrationId: clean(meta.integrationId),
    provider: normalizeProvider(meta.provider),
    securityMode: meta.securityMode,
    cadence: normalizeCadence(meta.cadence),
    cron: clean(meta.cron) || null,
    objectId: clean(meta.objectId) || null,
    rowName: clean(meta.rowName) || null,
    generatedAt: clean(meta.generatedAt) || null,
  };
  return `// ${SCHEDULER_ARTIFACT_MARKER} ${JSON.stringify(payload)}\n// GENERATED by the governed scheduler studio — do not hand-edit; re-provision to regenerate.`;
}

/** Parse the provenance banner back out of an artifact's source (drift guard). */
function parseArtifactBanner(source) {
  const text = String(source || "");
  const line = text.split("\n").find((l) => l.includes(SCHEDULER_ARTIFACT_MARKER));
  if (!line) return null;
  const json = line.slice(line.indexOf(SCHEDULER_ARTIFACT_MARKER) + SCHEDULER_ARTIFACT_MARKER.length).trim();
  try { return JSON.parse(json); } catch { return null; }
}

/**
 * Generate the deployable provider endpoint. The secret is read from the host
 * runtime env at run time — never inlined. The handler accepts the same
 * growthub-sandbox-run-v1 envelope the serverless delegation already sends.
 *
 * Security posture is HONEST and provider-appropriate (finding 7):
 *   - qstash-schedule → real Upstash-Signature (HS256 JWT) verification against
 *     QSTASH_CURRENT_SIGNING_KEY / QSTASH_NEXT_SIGNING_KEY. Missing/invalid
 *     signature is rejected. No comment claims security that isn't implemented.
 *   - supabase-edge → shared-secret check, explicitly labeled lower assurance.
 */
function generateSchedulerEndpointCode({ provider, integrationId, cron, cadence, authRef, objectId, rowName, generatedAt }) {
  const id = slugify(integrationId, "scheduler");
  const p = normalizeProvider(provider);
  const cadenceNorm = normalizeCadence(cadence);
  const cronText = clean(cron);
  const securityMode = p === "qstash-schedule" ? "qstash-verified" : "shared-secret";
  const banner = buildArtifactBanner({ integrationId: id, provider: p, securityMode, cadence: cadenceNorm, cron: cronText, objectId, rowName, generatedAt });

  if (p === "qstash-schedule") {
    return `${banner}
// QStash schedule destination for "${id}" (security: qstash-verified).
// Deploy as an HTTP endpoint (Next.js route / serverless function). QStash is
// pointed at its public URL and registered with cron "${cronText || "<set by provision>"}"
// (cadence "${cadenceNorm}") by POST /api/workspace/scheduler/provision.
//
// Security: verifies the real Upstash-Signature (HS256 JWT) over the request body
// against QSTASH_CURRENT_SIGNING_KEY / QSTASH_NEXT_SIGNING_KEY. Requests without a
// valid signature are rejected. No shared secret is trusted in this mode.
import crypto from "node:crypto";

function b64urlToBuf(s) { return Buffer.from(String(s).replace(/-/g, "+").replace(/_/g, "/"), "base64"); }
function b64url(buf) { return Buffer.from(buf).toString("base64").replace(/\\+/g, "-").replace(/\\//g, "_").replace(/=+$/, ""); }

function verifyUpstashSignature(token, rawBody, signingKey) {
  if (!token || !signingKey) return false;
  const parts = String(token).split(".");
  if (parts.length !== 3) return false;
  const [headerB64, payloadB64, sigB64] = parts;
  const expected = crypto.createHmac("sha256", signingKey).update(\`\${headerB64}.\${payloadB64}\`).digest();
  const got = b64urlToBuf(sigB64);
  if (expected.length !== got.length || !crypto.timingSafeEqual(expected, got)) return false;
  let payload;
  try { payload = JSON.parse(b64urlToBuf(payloadB64).toString("utf8")); } catch { return false; }
  const now = Math.floor(Date.now() / 1000);
  if (payload.exp && now > Number(payload.exp) + 5) return false;
  if (payload.nbf && now < Number(payload.nbf) - 5) return false;
  // body claim binds the signature to this exact payload (sha256, base64url).
  if (payload.body) {
    const bodyHash = b64url(crypto.createHash("sha256").update(rawBody).digest());
    if (bodyHash !== String(payload.body).replace(/=+$/, "")) return false;
  }
  return true;
}

export async function POST(request) {
  const token = request.headers.get("upstash-signature") || "";
  const rawBody = await request.text();
  const current = process.env.QSTASH_CURRENT_SIGNING_KEY || "";
  const next = process.env.QSTASH_NEXT_SIGNING_KEY || "";
  const verified = verifyUpstashSignature(token, rawBody, current) || verifyUpstashSignature(token, rawBody, next);
  if (!verified) return Response.json({ ok: false, exitCode: 1, error: "invalid or missing Upstash-Signature" }, { status: 401 });
  let body;
  try { body = JSON.parse(rawBody); } catch { return Response.json({ ok: false, exitCode: 1, error: "invalid JSON body" }, { status: 400 }); }
  if (body?.kind !== "growthub-sandbox-run-v1") {
    return Response.json({ ok: false, exitCode: 1, error: "expected growthub-sandbox-run-v1 envelope" }, { status: 400 });
  }
  // ── Your scheduled work goes here. Return the sandbox-run result shape.
  return Response.json({ ok: true, exitCode: 0, stdout: \`qstash scheduled run \${body.runId || ""} accepted by ${id}\`, durationMs: 0 });
}

export const dynamic = "force-dynamic";
`;
  }

  // supabase-edge → shared-secret destination (explicitly lower assurance).
  const candidates = authCandidates(authRef || id);
  return `${banner}
// Supabase Edge Function for "${id}" (security: shared-secret — LOWER ASSURANCE).
// Deploy: copy to supabase/functions/${id}/index.js, then \`supabase functions deploy ${id}\`.
// The recurring schedule is owned by Supabase (pg_cron / dashboard) — POST
// /api/workspace/scheduler/provision scaffolds + verifies this endpoint but does
// NOT create the Supabase schedule. Wire the cron in Supabase, then mark it
// confirmed in the cockpit.
//
// Security: shared-secret only (Authorization / x-api-key contains the secret).
// This is LOWER ASSURANCE than signed requests; rotate the secret regularly and
// prefer a signed provider where a stronger guarantee is required.
const ENV_CANDIDATES = ${JSON.stringify(candidates)};
function readSecret(env) {
  for (const key of ENV_CANDIDATES) { const v = env.get(key); if (v) return v; }
  return "";
}

Deno.serve(async (req) => {
  const json = (body, status = 200) => new Response(JSON.stringify(body), { status, headers: { "content-type": "application/json" } });
  const secret = readSecret(Deno.env);
  if (secret) {
    const header = req.headers.get("authorization") || req.headers.get("x-api-key") || "";
    if (!header.includes(secret)) return json({ ok: false, exitCode: 1, error: "unauthorized" }, 401);
  }
  let body;
  try { body = await req.json(); } catch { return json({ ok: false, exitCode: 1, error: "invalid JSON body" }, 400); }
  if (body?.kind !== "growthub-sandbox-run-v1") {
    return json({ ok: false, exitCode: 1, error: "expected growthub-sandbox-run-v1 envelope" }, 400);
  }
  // ── Your scheduled work goes here. Return the sandbox-run result shape.
  return json({ ok: true, exitCode: 0, stdout: \`scheduled run \${body.runId || ""} accepted by ${id}\`, durationMs: 0 });
});
`;
}

/**
 * Build an inert scheduler.create proposal. Carries the target artifact path,
 * the generated endpoint code, the api-registry binding the serverless
 * delegation targets, and the cron the provision route registers. Nothing is
 * written or scheduled until the provision lane runs (gated + confirm).
 */
function buildSchedulerProposal(input = {}) {
  const integrationId = slugify(input.integrationId, "scheduler");
  const provider = normalizeProvider(input.provider);
  const caps = providerCaps(provider);
  const cadence = normalizeCadence(input.cadence);
  const { cron, error: cronError } = cadenceToCron(cadence, { cron: input.cron, timezone: input.timezone });
  const authRef = clean(input.authRef) || caps.authRefDefault;
  const target = resolveSchedulerFilePath(integrationId, provider);
  const securityMode = provider === "qstash-schedule" ? "qstash-verified" : "shared-secret";
  const code = generateSchedulerEndpointCode({
    provider, integrationId, cron, cadence, authRef,
    objectId: input.objectId, rowName: input.rowName, generatedAt: input.generatedAt,
  });

  return {
    type: SCHEDULER_PROPOSAL_TYPE,
    affectedField: SCHEDULER_AFFECTED_FIELD,
    rationale: `Provision a ${provider} scheduler for "${integrationId}" running ${cadence}${cron ? ` (${cron})` : ""}.`,
    confidence: 0.85,
    target,
    language: "javascript",
    securityMode,
    code,
    security: [
      "Server artifact — only written in filesystem mode (read-only runtimes get a 409 + guidance).",
      provider === "qstash-schedule"
        ? "Verifies the real Upstash-Signature (HS256) against QSTASH_CURRENT/NEXT_SIGNING_KEY — no shared secret trusted."
        : "Shared-secret check (lower assurance); secret read from env at run time, never inlined.",
      `Path confined to ${SCHEDULER_DIR}.`,
    ],
    contract: {
      inputs: [`cadence "${cadence}"`, cron ? `cron "${cron}"` : "no cron (manual)", `authRef env (${authCandidates(authRef).join(", ") || "none"})`],
      output: "An HTTP endpoint that accepts growthub-sandbox-run-v1 and returns the sandbox-run result shape.",
      createsProviderSchedule: caps.createsProviderSchedule,
      schedulingMode: caps.schedulingMode,
    },
    registryBinding: {
      integrationId,
      connectorKind: SCHEDULER_CONNECTOR_KIND,
      schedulerProvider: provider,
      method: "POST",
      authRef,
      baseUrl: clean(input.baseUrl),
      endpoint: clean(input.endpoint),
      cronExpression: cron || "",
    },
    scheduleSpec: {
      provider,
      cadence,
      cron: cron || null,
      cronError: cronError || null,
      timezone: clean(input.timezone) || "UTC",
      createsProviderSchedule: caps.createsProviderSchedule,
      schedulingMode: caps.schedulingMode,
    },
    payload: {
      integrationId,
      provider,
      cadence,
      cron: cron || "",
      authRef,
      filename: target.filename,
    },
  };
}

function validateSchedulerProposal(proposal) {
  if (!proposal || proposal.type !== SCHEDULER_PROPOSAL_TYPE) {
    return { ok: false, error: "not a scheduler.create proposal" };
  }
  if (proposal.affectedField !== SCHEDULER_AFFECTED_FIELD) {
    return { ok: false, error: `scheduler.create affectedField must be "${SCHEDULER_AFFECTED_FIELD}"` };
  }
  const providerRaw = clean(proposal.payload?.provider || proposal.scheduleSpec?.provider).toLowerCase();
  if (!KNOWN_SCHEDULER_PROVIDERS.includes(providerRaw)) {
    return { ok: false, error: `scheduler provider must be one of ${KNOWN_SCHEDULER_PROVIDERS.join(", ")}` };
  }
  const target = (proposal.target && proposal.target.ok)
    ? proposal.target
    : resolveSchedulerFilePath(proposal.payload?.integrationId, providerRaw);
  if (!target || !target.ok) {
    return { ok: false, error: target?.error || "invalid scheduler target path" };
  }
  const code = clean(proposal.code);
  if (!code) return { ok: false, error: "scheduler code is empty" };
  if (!target.filename.endsWith(".js")) {
    return { ok: false, error: "scheduler file must have a .js extension" };
  }
  if (proposal.scheduleSpec?.cronError) {
    return { ok: false, error: proposal.scheduleSpec.cronError };
  }
  return { ok: true, error: null, target };
}

export {
  SCHEDULER_PROPOSAL_TYPE,
  SCHEDULER_AFFECTED_FIELD,
  SCHEDULER_DIR,
  SCHEDULER_PROVIDERS,
  SCHEDULER_CONNECTOR_KIND,
  SCHEDULER_ARTIFACT_MARKER,
  SCHEDULER_ARTIFACT_VERSION,
  normalizeProvider,
  resolveSchedulerFilePath,
  generateSchedulerEndpointCode,
  buildSchedulerProposal,
  validateSchedulerProposal,
  buildArtifactBanner,
  parseArtifactBanner,
};
